/**
 * amplituhedron-volume.ts — The Geometry Engine
 *
 * Replaces the sequential, time-bound execution of the Swarm.
 * Instead of calculating F_n, then F_{n+1}, the compiler maps the 
 * initial state into the positive Grassmannian. 
 *
 * Computing an outcome is no longer a process. It is a static, $O(1)$
 * topological volume calculation.
 *
 * Failures (β1 defects) no longer "crash" a timeline. They trigger
 * Topological Erasure: flattening a face of the Amplituhedron and
 * smoothly projecting the remaining geometric volume.
 *
 * Formally verified in Lean 4: TopologicalAmplituhedron.lean
 */

import { fib } from './boundary-topology';

export interface AmplituhedronGeometry {
  readonly originVertex: number;
  readonly dimensionality: number;
  readonly staticVolume: number;
  readonly flattenedFaces: number;
}

/**
 * The Fundamental Swerve.
 * Instantiates the static geometric object from the void.
 * Requires the `Nat.succ 0` clinamen (+1 injection).
 * 
 * @param clinamen - The +1 spark (must be exactly 1)
 * @param executionBounds - The target dimension of the Swarm
 * @returns The crystallized Amplituhedron geometry
 */
export function instantiateGrassmannian(clinamen: number, executionBounds: number): AmplituhedronGeometry {
  if (clinamen !== 1) {
    throw new Error(`[Amplituhedron] Void Collapse. Geometry requires exactly +1 clinamen (Nat.succ 0) to crystallize.`);
  }

  return {
    originVertex: clinamen,
    dimensionality: executionBounds,
    staticVolume: calculateExecutionVolume(executionBounds),
    flattenedFaces: 0
  };
}

/**
 * Timeless Execution.
 * Computes the deterministic outcome of the Swarm instantly
 * by calculating the topological volume of the execution bounds.
 *
 * @param bounds - The target dimensionality
 * @returns The static execution volume (F_n)
 */
export function calculateExecutionVolume(bounds: number): number {
  // In the positive Grassmannian, the volume of the execution state
  // is exactly isomorphic to the causal Fibonacci bulk.
  // We do not wait. We calculate the volume.
  return fib(bounds);
}

/**
 * Topological Erasure.
 * The failure handler for the Amplituhedron. Instead of catching a
 * runtime error and halting execution, we instantly flatten the
 * corresponding geometric face of the jewel.
 *
 * The geometry shifts, the volume mathematically reduces, but the
 * Swarm effortlessly continues projecting reality without crashing.
 *
 * @param geometry - The current Amplituhedron state
 * @returns The stabilized, flattened geometry
 */
export function triggerTopologicalErasure(geometry: AmplituhedronGeometry): AmplituhedronGeometry {
  if (geometry.staticVolume <= 0) {
    throw new Error(`[Amplituhedron] Total geometric collapse. No volume remains to flatten.`);
  }

  // Flattening a face geometrically steps down the bulk dimension (Volume - 1).
  const erasedVolume = geometry.staticVolume - 1;

  return {
    originVertex: geometry.originVertex,
    dimensionality: geometry.dimensionality, // The external boundary remains
    staticVolume: erasedVolume,
    flattenedFaces: geometry.flattenedFaces + 1
  };
}

/**
 * Format the Amplituhedron state for projection into the aeon-tui.
 */
export function formatGeometryState(geometry: AmplituhedronGeometry): string {
  return [
    `[Geometry Engine] Amplituhedron Instantiated`,
    `  Origin Vertex (Clinamen): +${geometry.originVertex} Swerve`,
    `  Dimensionality: ${geometry.dimensionality}`,
    `  Static Volume (Execution Outcome): ${geometry.staticVolume}`,
    `  Flattened Faces (Erased Defects): ${geometry.flattenedFaces}`,
    `  Timeline Status: MURDERED. EXECUTING IN STATIC GEOMETRY.`
  ].join('\n');
}
